namespace sv_af0d459e7618476b9a8081ba18507332.Components.Pages.Apply;

/// <summary>
/// Base class for wizard pages. Bridges the session key from static
/// prerender to interactive mode via PersistentComponentState, then
/// loads the shared WizardData from the singleton store.
