@page "/apply/review"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-3">
    <div class="card-header"><strong>Personal Information</strong></div>
    <div class="card-body">
        <p><strong>Name:</strong> @Data.Name</p>
        <p><strong>Email:</strong> @Data.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Work Experience</strong></div>
    <div class="card-body">
        @if (Data.JobHistory.Count == 0)
        {
            <p class="text-muted">No entries.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var job in Data.JobHistory)
                {
                    <li class="list-group-item">
                        <strong>@job.Title</strong> at @job.Company
                        @if (!string.IsNullOrWhiteSpace(job.Duration))
                        {
                            <span class="text-muted">(@job.Duration)</span>
                        }
                    </li>
                }
            </ul>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>References</strong></div>
    <div class="card-body">
        @if (Data.References.Count == 0)
        {
            <p class="text-muted">No entries.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var r in Data.References)
                {
                    <li class="list-group-item">
                        <strong>@r.Name</strong> – @r.Email
                        @if (!string.IsNullOrWhiteSpace(r.Relationship))
                        {
                            <span class="text-muted">(@r.Relationship)</span>
                        }
                    </li>
                }
            </ul>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/apply/references")'>
        &laquo; Back
    </button>
    <button class="btn btn-success" @onclick="Submit">
        Submit Application
    </button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        Your application has been submitted successfully!
    </div>
}

@code {
    private bool _submitted;

    private void Submit()
    {
        // In a real app, persist the data to a database here.
        _submitted = true;
    }
}

