﻿@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_af0d459e7618476b9a8081ba18507332.Services.WizardStateStore WizardStore

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @{
                var path = Nav.ToAbsoluteUri(Nav.Uri).AbsolutePath;
                var isWizard = path.StartsWith("/apply/");
            }
            @if (isWizard)
            {
                @* Progress bar — rendered statically on each navigation *@
                var currentStep = path switch
                {
                    var p when p.StartsWith("/apply/personal-info") => 1,
                    var p when p.StartsWith("/apply/experience") => 2,
                    var p when p.StartsWith("/apply/references") => 3,
                    var p when p.StartsWith("/apply/review") => 4,
                    _ => 0
                };
                var sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
                var data = WizardStore.GetOrCreate(sessionId);

                <nav class="wizard-progress" aria-label="Application progress">
                    <span class="wizard-step-label">Step @currentStep of 4</span>
                    <ol class="wizard-steps">
                        @foreach (var (step, label, href, complete) in new[]
                        {
                            (1, "Personal Info", "/apply/personal-info", data.Step1Complete),
                            (2, "Experience",    "/apply/experience",    data.Step2Complete),
                            (3, "References",    "/apply/references",    data.Step3Complete),
                            (4, "Review",        "/apply/review",        false)
                        })
                        {
                            var css = step == currentStep ? "active"
                                    : complete           ? "complete"
                                    :                      "";

                            <li class="wizard-step @css">
                                <a href="@href">@label</a>
                            </li>
                        }
                    </ol>
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

